  ('dietitian-moex-02193', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某大專生健康飲食態度問卷調查，間隔三星期前後填寫同份問卷各一次，兩次問卷之相關係數為0.1，下 列對此問卷之推斷何者正確？', '["信度不佳", "效度不佳", "難度過高", "鑑別度過低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02194', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '練習教學法（practice instruction）的實施步驟，下列順序何者正確？①教師示範  ②學習者模仿  ③評量', '["引起動機  ⑤反覆練習", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02195', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '張同學了解鈣對身體的重要性後，決定要開始喝鮮乳，但是因為住校不容易買到鮮乳，因此影響原先喝 鮮乳的計畫。就健康信念模式（Health beliefs model）而言，影響張同學無法喝鮮乳的是那一個因素？', '["個體的認知（Individual perceptions）", "修正因素（Modifying factors）", "行動的可能性（Likelihood of action）", "結果評價（Outcome evaluation）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02196', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '社會行銷（social marketing）理論中由五個主要元素組成，簡稱為5 Ps，下列何者不屬於其中之一？', '["產品（product）", "價格（price）", "計畫（planning）", "定位（positioning）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02197', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '諮商個案出現自我矛盾時：「我希望減重，但是我沒有信心達成，因為我常參加宴會，忍不住多吃一點」。 營養師說：「你想減輕體重，但是你又不願意控制你在宴會中所吃的食物量，你覺得該怎麼做呢？」此 時營養師使用的談話，較符合下列何種諮商技巧？', '["指示", "面質", "澄清", "歸因"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02198', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '接受糖尿病飲食營養教育後，病人能分辨那些食物是屬於低GI的食物，這是屬於下列何種改變？', '["行為", "知識", "態度", "環境"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02199', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '衛生福利部制定「2025 衛生福利政策白皮書」，作為全民健康平等的施政藍圖，此為國家公共衛生的那 一種規劃？', '["方案規劃（program planning）", "操作規劃（operational planning）", "策略規劃（strategic planning）", "執行規劃（active planning）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02200', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某社區營養師在提出社區營養服務計畫時，以SWOT分析此項計畫的優勢（strength, S）、劣勢（weakness, W）、機會（opportunity, O）、威脅（threat, T）情勢，該團隊皆為在地人且地方語言流利，社區得到政 府經費補助，就此分析屬於下列那一種情勢？', '["ST", "SO", "WT", "WO"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02201', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '跨組織的合作是幫助社區營養計畫達成的有效步驟。當中與其他人或團體交換資訊、分享資源是屬於下 列何種方式？', '["聯盟", "異業結盟", "脈絡運作", "轉介系統"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02202', 'dietitian', 'dietitian-moex-106-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據1993～1996年與2005～2008年兩次臺灣國民營養健康狀況變遷調查結果中，下列敘述何者錯誤？', '["國人十多年來的血中葉酸濃度無顯著變化", "大於65歲之老人同半胱胺酸血症盛行率增高", "肥胖及代謝症候群盛行率，女性比男性增加快速", "超過半數以上的民眾，血清維生素D濃度是低於正常值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "055f81a9ea11", "answer_pdf_sha1": "81c6ef946dbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
